insert into offmarket.business_scores (business_id, score_run_id, layer1_base_rate, layer1_comment, layer2_sellability, layer2_comment, layer3_behavioral_trigger, layer3_comment, layer4_market_pull, layer4_comment, final_score, final_tier, final_comment, value_add_thesis, confidence, data_completeness) values
('b74891d9-0f7e-5fb0-a3c5-125edafc6cc5', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 86, 'Dr. Woolwine (UT Health San Antonio DDS) has practiced in the same Austin building since 1985 (~41 yrs) — tenure proxy ~64-68, squarely in the natural-exit window; solo owner with no associate. Strong base-rate signal. Medium confidence (proxy age).', 76, 'Clean ~41-yr solo general/family/implant/cosmetic practice on W 38th St (near central Austin), recurring hygiene base, loyal multigenerational patients (''our families have been going to him for 30+ yrs''), clean record — a highly sellable, bankable solo practice. Recently rebranded to ''The Grove'', which can be a tidy-up-before-sale move.', 70, 'Strong coasting profile: solo provider with no associate, same building for 41 yrs, recent cosmetic rebrand but otherwise dated presence, no visible recent expansion or hiring, owner near a natural exit. Healthy, disengaged-growth — not distress.', 88, 'Central Austin (78731, near 38th St/Mopac) is a premium, supply-constrained catchment; Austin is a top DSO/PE dental market and a clean long-tenured solo GP there is a prime SBA-financed acquisition.', 79, 'A_acquire_self', 'Dr. Michael V. Woolwine, ~66 (license_tenure_proxy), runs Michael V. Woolwine, D.D.S. (The Grove Austin Family Dentistry) in Austin, Travis County. Dr. Woolwine (UT Health San Antonio DDS) has practiced in the same Austin building since 1985 (~41 yrs) — tenure proxy ~64-68, squarely in the natural-exit window; solo owner with no associate. Strong base-rate signal. Medium confidence (proxy age). Strong coasting profile: solo provider with no associate, same building for 41 yrs, recent cosmetic rebrand but otherwise dated presence, no visible recent expansion or hiring, owner near a natural exit. Healthy, disengaged-growth — not distress. Central Austin (78731, near 38th St/Mopac) is a premium, supply-constrained catchment; Austin is a top DSO/PE dental market and a clean long-tenured solo GP there is a prime SBA-financed acquisition. Composite 79/100. Tier A — Gideon should pursue this one directly.', 'AI front desk + recall automation, online scheduling, modern PMS migration, automated reviews, plus an associate-to-owner glide path; the recent rebrand gives a marketing platform to build on — credible 1.5-2x EBITDA path over 18-24 months.', 'medium', 0.6),
('1889d312-f865-5771-b144-0dcc5b7879be', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 38, 'The practice itself has served South Austin 30+ yrs, but Dr. Baucum bought it from Dr. Richard Ross in October 2008 (~18 yrs as owner) and is mid-career — tenure proxy ~44-50, not at a natural-exit window. Low-medium L1.', 76, 'Clean 30+-yr South Austin (78745) general/family practice with a deep recurring base inherited from a long-tenured predecessor, ~6 staff, clean record — a real, financeable, attractive practice; the owner just isn''t a seller.', 32, 'Not coasting — Dr. Baucum took the practice over relatively recently and is mid-career; web presence reasonably maintained. Low-moderate L3.', 86, 'South Austin 78745 is a hot, fast-gentrifying catchment with strong DSO interest, but a mid-career owner isn''t a near-term target.', 53, 'C_watch', 'Dr. Darryl C. Baucum, ~46 (license_tenure_proxy), runs Baucum Family Dentistry (Darryl C. Baucum, DDS) in Austin, Travis County. The practice itself has served South Austin 30+ yrs, but Dr. Baucum bought it from Dr. Richard Ross in October 2008 (~18 yrs as owner) and is mid-career — tenure proxy ~44-50, not at a natural-exit window. Low-medium L1. Not coasting — Dr. Baucum took the practice over relatively recently and is mid-career; web presence reasonably maintained. Low-moderate L3. South Austin 78745 is a hot, fast-gentrifying catchment with strong DSO interest, but a mid-career owner isn''t a near-term target. Composite 53/100. Tier C — re-score in ~90 days.', 'N/A near-term — recent-ish owner. Watch / re-score in ~2-3 yrs.', 'low', 0.4),
('c0ab6c95-357f-5747-8212-8c32eef89049', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 36, 'The practice has run since ~1994 (~32 yrs), but current owner Dr. Diemer (Texas A&M class of 2001, dental grad ~2005) is mid-career — tenure proxy ~44-48, not at a natural-exit window. Low-medium L1.', 76, 'Clean ~32-yr North Austin (78728) general/family practice with a strong recurring base and good reviews (4.8, 112 reviews), ~6 staff, clean record — a real, financeable, attractive practice; the owner just isn''t a seller.', 32, 'Not coasting — mid-career owner, active web presence, healthy review velocity. Low-moderate L3.', 85, 'North Austin / Wells Branch (78728) is a populous, growing catchment with strong DSO interest, but a mid-career owner isn''t a near-term target.', 52, 'C_watch', 'Dr. Kara B. Diemer, ~47 (license_tenure_proxy), runs Austin Family Dentistry (Kara B. Diemer, DDS) in Austin, Travis County. The practice has run since ~1994 (~32 yrs), but current owner Dr. Diemer (Texas A&M class of 2001, dental grad ~2005) is mid-career — tenure proxy ~44-48, not at a natural-exit window. Low-medium L1. Not coasting — mid-career owner, active web presence, healthy review velocity. Low-moderate L3. North Austin / Wells Branch (78728) is a populous, growing catchment with strong DSO interest, but a mid-career owner isn''t a near-term target. Composite 52/100. Tier C — re-score in ~90 days.', 'N/A near-term — owner not winding down. Watch.', 'low', 0.4),
('ab479f50-fb44-54a5-93df-a5dad91371a4', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 80, 'Dr. Matson received his DDS from UT Dental Branch Houston in 1989 and has run the practice continuously since 8/17/1989 (~36 yrs); license-tenure proxy ~62-65 — squarely in the natural-exit window; solo owner with no associate. Medium confidence (proxy age).', 76, 'Clean ~36-yr solo general/ortho/cosmetic family practice in SE Houston (Hobby/77061), recurring hygiene base, accepts a range of insurance (volume practice), ~6 staff, clean record — a sellable, bankable solo practice. Working-class catchment trims the multiple modestly.', 66, 'Strong coasting profile: solo provider with no associate, 36 yrs in the same location, dated web brand, no visible recent expansion or hiring, owner near a natural exit. Healthy, disengaged-growth — not distress.', 82, 'SE Houston/Hobby has steady DSO interest (volume general practices roll up well); a clean long-tenured solo GP there is a clean SBA-financed bolt-on. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 75, 'B_forward', 'Dr. Bruce A. Matson, ~62 (license_tenure_proxy), runs Bruce A. Matson, D.D.S. in Houston, Harris County. Dr. Matson received his DDS from UT Dental Branch Houston in 1989 and has run the practice continuously since 8/17/1989 (~36 yrs); license-tenure proxy ~62-65 — squarely in the natural-exit window; solo owner with no associate. Medium confidence (proxy age). Strong coasting profile: solo provider with no associate, 36 yrs in the same location, dated web brand, no visible recent expansion or hiring, owner near a natural exit. Healthy, disengaged-growth — not distress. SE Houston/Hobby has steady DSO interest (volume general practices roll up well); a clean long-tenured solo GP there is a clean SBA-financed bolt-on. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 75/100. Tier B — hand to the buyer / searcher community.', 'AI front desk + recall automation + online scheduling + modern PMS + automated reviews; associate hire on a buy-in path — credible 1.5-2x EBITDA path over 18-24 months.', 'medium', 0.55),
('ee4a8242-063c-5429-9f5c-0e942ebf6826', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 76, 'Dr. Salha has 31+ years of experience (patients report seeing him for 25 yrs); license-tenure proxy ~58-62 — entering the natural-exit window. Solo, works one patient at a time, no hygiene assistant (does his own cleanings) — a small, owner-dependent practice. Medium-low confidence (proxy age).', 68, 'Clean 31-yr solo cosmetic/restorative/implant/full-mouth-reconstruction practice in the affluent San Felipe/Tanglewood corridor (77063), recurring base, multi-year ''Top Doctor'' awards, clean record — sellable, but its small footprint and one-chair-at-a-time model cap sellability and the SBA size estimate.', 64, 'Coasting tells: solo provider with no assistant, small owner-dependent operation, dated web presence, no visible recent expansion or hiring, owner near a natural exit. Healthy practice, classic disengaged-growth — not distress.', 84, 'San Felipe/Tanglewood Houston (77063) is a premium corridor with strong DSO and individual-buyer demand; a high-end restorative solo practice there is attractive though small. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 72, 'B_forward', 'Dr. Fadi C. Salha, ~60 (license_tenure_proxy), runs Fadi C. Salha, D.D.S. (Houston Dental Care) in Houston, Harris County. Dr. Salha has 31+ years of experience (patients report seeing him for 25 yrs); license-tenure proxy ~58-62 — entering the natural-exit window. Solo, works one patient at a time, no hygiene assistant (does his own cleanings) — a small, owner-dependent practice. Medium-low confidence (proxy age). Coasting tells: solo provider with no assistant, small owner-dependent operation, dated web presence, no visible recent expansion or hiring, owner near a natural exit. Healthy practice, classic disengaged-growth — not distress. San Felipe/Tanglewood Houston (77063) is a premium corridor with strong DSO and individual-buyer demand; a high-end restorative solo practice there is attractive though small. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 72/100. Tier B — hand to the buyer / searcher community.', 'AI front desk + recall automation + online scheduling, add a hygienist to free the doctor for production, modern PMS, automated reviews — credible EBITDA uplift over 18-24 months by lifting throughput.', 'low', 0.5),
('a4ed9ff6-7143-58df-8722-06d0d1d9ab42', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 40, 'Practice founded 2000 (~26 yrs), but founder Dr. Nazari graduated 1998 (~28 yrs licensed) and is clearly mid-career; license-tenure proxy ~50-54 — not at a natural-exit window. The multi-doctor, all-in-one-center model is a builder''s posture, not a coaster''s. Low-medium L1.', 78, 'Genuinely strong asset: a ~26-yr multi-doctor (5+ dentists) full-service dental center in N Houston/Northline with a deep recurring base, ~18 staff, clean record — financeable and meaningful size. The constraint is the owner isn''t a seller.', 30, 'Not coasting — actively growing multi-provider center, fresh marketing, recent reviews. Low L3.', 82, 'N Houston/Northline is a solid DSO catchment and a 5-dentist center is a prime roll-up target — but with a non-selling builder-owner this is a watch, not an actionable target. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 53, 'C_watch', 'Drs. Behzad Nazari, Eric Choudhury, Wael Kanaan, Simon Samo, Sanjar Nadiri, ~52 (license_tenure_proxy), runs Antoine Dental Center (Behzad Nazari, DDS) in Houston, Harris County. Practice founded 2000 (~26 yrs), but founder Dr. Nazari graduated 1998 (~28 yrs licensed) and is clearly mid-career; license-tenure proxy ~50-54 — not at a natural-exit window. The multi-doctor, all-in-one-center model is a builder''s posture, not a coaster''s. Low-medium L1. Not coasting — actively growing multi-provider center, fresh marketing, recent reviews. Low L3. N Houston/Northline is a solid DSO catchment and a 5-dentist center is a prime roll-up target — but with a non-selling builder-owner this is a watch, not an actionable target. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 53/100. Tier C — re-score in ~90 days.', 'N/A near-term — owner is a builder, not a seller. Watch / a DSO-partnership candidate down the line.', 'low', 0.4),
('2ce5dc07-dfe7-5b68-9b4a-3806c94fb11a', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 48, 'Dr. Wade opened her downtown Houston practice in 2000 (~25 yrs as owner; prior US Army dental officer service) — license-tenure proxy ~52-58, approaching but not yet in the prime exit window. Medium-low confidence (proxy age).', 70, 'Clean 25-yr solo cosmetic-focused practice in downtown Houston (77002), award-winning (Houston Top Dentist 2009/2012, Pinnacle Award), recurring base, clean record — a real, financeable solo cosmetic practice; smaller footprint caps it.', 44, 'Mixed: solo provider, modest review velocity, and a 25-yr single location lean coasting; but the owner is still active in adjacent ventures (nonprofit, product line) and reasonably visible — moderate-low L3.', 84, 'Downtown Houston cosmetic practice — premium positioning, strong DSO/individual-buyer demand. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 58, 'C_watch', 'Dr. Ka-Ron Y. Wade, ~55 (license_tenure_proxy), runs The Dentistry of Dr. Ka-Ron Y. Wade in Houston, Harris County. Dr. Wade opened her downtown Houston practice in 2000 (~25 yrs as owner; prior US Army dental officer service) — license-tenure proxy ~52-58, approaching but not yet in the prime exit window. Medium-low confidence (proxy age). Mixed: solo provider, modest review velocity, and a 25-yr single location lean coasting; but the owner is still active in adjacent ventures (nonprofit, product line) and reasonably visible — moderate-low L3. Downtown Houston cosmetic practice — premium positioning, strong DSO/individual-buyer demand. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 58/100. Tier C — re-score in ~90 days.', 'AI front desk + recall automation + online scheduling + modern PMS + automated reviews; structured cosmetic-case marketing — incremental EBITDA over 2 yrs. Re-score in ~12 months as the owner ages further.', 'low', 0.4),
('9928b472-f705-591e-83e8-2b74be5d4ec2', '38f59bde-c3a1-5f3a-8434-e0f6ef717462', 36, 'Dr. Tummala earned a BS in pharmacy in 1998 before dental school, implying a dental grad ~2005-2008 and a mid-career owner; license-tenure proxy ~45-50 — not at a natural-exit window. Low-medium L1.', 78, 'Clean, very well-reviewed (532 Birdeye reviews) Meyerland (77096) general/cosmetic/implant/ortho practice with a deep recurring base, ~7 staff, modern tech — a real, financeable, attractive practice; the owner just isn''t a seller.', 30, 'Not coasting — high review velocity, modern tech, active marketing, mid-career owner. Low L3.', 84, 'Meyerland Houston (77096) is a desirable, stable catchment with strong DSO interest; a 500+-review practice is a prized bolt-on. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite.', 52, 'C_watch', 'Dr. Chiranjeevi Tummala, ~48 (license_tenure_proxy), runs Meyerland Family Dentistry, P.C. (Chiranjeevi Tummala, DDS) in Houston, Harris County. Dr. Tummala earned a BS in pharmacy in 1998 before dental school, implying a dental grad ~2005-2008 and a mid-career owner; license-tenure proxy ~45-50 — not at a natural-exit window. Low-medium L1. Not coasting — high review velocity, modern tech, active marketing, mid-career owner. Low L3. Meyerland Houston (77096) is a desirable, stable catchment with strong DSO interest; a 500+-review practice is a prized bolt-on. Industry context: dental is ~30%+ DSO-penetrated and rising; Houston/Dallas/Austin are all active DSO/PE roll-up metros with strong SBA-7(a) financeability and high ETA/search-fund appetite. Composite 52/100. Tier C — re-score in ~90 days.', 'N/A near-term — owner not winding down. Watch.', 'low', 0.4)
